import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';

/**
 * Hook for live trading signal feed.
 * Polls /api/signals/latest every 30s with auto-refresh.
 * Supports region, strategy, and direction filtering.
 */
export default function useSignals({ autoRefresh = true, intervalMs = 30000 } = {}) {
  const [signals, setSignals] = useState([]);
  const [strategies, setStrategies] = useState([]);
  const [count, setCount] = useState(0);
  const [signalsGeneratedAt, setSignalsGeneratedAt] = useState(0);
  const [loading, setLoading] = useState(true);
  const hasLoaded = useRef(false);

  const fetchSignals = useCallback(async (opts = {}) => {
    if (!hasLoaded.current) setLoading(true);
    const params = new URLSearchParams();
    if (opts.region) params.set('region', opts.region);
    if (opts.strategies) params.set('strategies', opts.strategies);
    // Always include non-promoted for a full view
    params.set('promoted_only', opts.promotedOnly !== false ? 'true' : 'false');
    const qs = params.toString();
    const data = await api(`/signals/latest${qs ? '?' + qs : ''}`);
    if (data) {
      const arr = Array.isArray(data.signals) ? data.signals : [];
      setSignals(arr);
      setCount(data.count || arr.length);
      setSignalsGeneratedAt(data.signals_generated_at || 0);
    }
    setLoading(false);
    hasLoaded.current = true;
  }, []);

  const fetchStrategies = useCallback(async () => {
    const data = await api('/signals/strategies');
    if (data && Array.isArray(data.strategies)) {
      setStrategies(data.strategies);
    }
  }, []);

  useEffect(() => {
    fetchSignals();
    fetchStrategies();
    if (autoRefresh) {
      const iv = setInterval(() => fetchSignals(), intervalMs);
      return () => clearInterval(iv);
    }
  }, [fetchSignals, fetchStrategies, autoRefresh, intervalMs]);

  return {
    signals,
    strategies,
    count,
    signalsGeneratedAt,
    loading,
    refresh: fetchSignals,
    fetchSignals,
    fetchStrategies,
  };
}
