import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import useSignals from '../hooks/useSignals';
import useIsMobile from '../hooks/useIsMobile';
import usePageTitle from '../hooks/usePageTitle';
import ExportBar from '../components/ExportBar';
import LoadingState from '../components/LoadingState';
import { SkeletonMobile } from '../components/SkeletonUI';
import RegulatoryDisclaimer from '../components/RegulatoryDisclaimer';
import { tokens } from '../styles/tokens';
import { api } from '../utils/api';
import { getApiBase } from '../utils/platform';

const colors = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
  gold: '#F59E0B',
};
const mono = tokens.font.mono;

// ── Signal tier classification ──
// Maps confidence to display tier: ULTRA (>=0.95), HIGH CONVICTION (>=0.70), STANDARD (<0.70)
function getSignalTier(confidence) {
  const c = confidence || 0;
  if (c >= 0.95) return { label: 'ULTRA', color: colors.gold, bg: 'rgba(245,158,11,0.15)', border: 'rgba(245,158,11,0.35)' };
  if (c >= 0.70) return { label: 'HIGH CONVICTION', color: colors.blue, bg: 'rgba(96,165,250,0.15)', border: 'rgba(96,165,250,0.35)' };
  return { label: 'STANDARD', color: colors.textSecondary, bg: 'rgba(139,148,158,0.12)', border: 'rgba(139,148,158,0.25)' };
}

function TierBadge({ confidence }) {
  const tier = getSignalTier(confidence);
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      padding: '2px 8px', borderRadius: 4, fontSize: 9, fontWeight: 700,
      background: tier.bg, color: tier.color, border: `1px solid ${tier.border}`,
      fontFamily: mono, letterSpacing: '0.08em', whiteSpace: 'nowrap',
    }}>
      {tier.label === 'ULTRA' && (
        <span style={{ width: 5, height: 5, borderRadius: '50%', background: tier.color, animation: 'signal-pulse 1s ease-in-out infinite' }} />
      )}
      {tier.label}
    </span>
  );
}

// ── Signal age classification ──
function getSignalAge(dateStr, generatedAt) {
  const now = Date.now() / 1000;
  let ageSeconds;
  if (generatedAt && generatedAt > 0) {
    ageSeconds = now - generatedAt;
  } else if (dateStr) {
    const d = new Date(dateStr);
    ageSeconds = (now - d.getTime() / 1000);
  } else {
    return { label: 'Unknown', color: colors.textSecondary, level: 'unknown' };
  }

  const ageMinutes = ageSeconds / 60;
  if (ageMinutes < 5) return { label: 'Fresh', color: colors.green, level: 'fresh' };
  if (ageMinutes < 30) return { label: `${Math.round(ageMinutes)}m ago`, color: colors.blue, level: 'recent' };
  if (ageMinutes < 60) return { label: 'Stale', color: colors.amber, level: 'stale' };
  const hours = Math.round(ageMinutes / 60);
  return { label: `Expired (${hours}h)`, color: colors.red, level: 'expired' };
}

function AgeBadge({ age }) {
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      padding: '2px 8px', borderRadius: 12, fontSize: 10, fontWeight: 600,
      background: `${age.color}18`, color: age.color, fontFamily: mono,
    }}>
      <span style={{
        width: 6, height: 6, borderRadius: '50%', background: age.color,
        ...(age.level === 'fresh' ? { animation: 'signal-pulse 1.5s ease-in-out infinite' } : {}),
      }} />
      {age.label}
    </span>
  );
}

function DirectionBadge({ direction }) {
  const isBuy = direction?.toLowerCase() === 'long' || direction?.toLowerCase() === 'buy';
  return (
    <span style={{
      display: 'inline-block', padding: '2px 10px', borderRadius: 14,
      fontSize: 11, fontWeight: 700, fontFamily: mono, letterSpacing: '0.05em',
      background: isBuy ? `${colors.green}18` : `${colors.red}18`,
      color: isBuy ? colors.green : colors.red,
    }}>
      {isBuy ? 'BUY' : 'SELL'}
    </span>
  );
}

function ConfidenceBar({ value }) {
  const pct = Math.round((value || 0) * 100);
  const barColor = pct >= 95 ? colors.gold : pct >= 70 ? colors.green : pct >= 50 ? colors.amber : colors.red;
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
      <div style={{
        width: 50, height: 6, background: colors.surface2, borderRadius: 3, overflow: 'hidden',
      }}>
        <div style={{
          width: `${Math.min(100, pct)}%`, height: '100%', background: barColor,
          borderRadius: 3, transition: 'width 0.3s ease',
        }} />
      </div>
      <span style={{ fontSize: 11, fontWeight: 600, color: barColor, fontFamily: mono }}>
        {pct}%
      </span>
    </div>
  );
}

// ── SSE Connection status badge ──
function ConnectionBadge({ status }) {
  const config = {
    connected: { label: 'SSE LIVE', color: colors.green, pulse: true },
    polling: { label: 'POLLING', color: colors.amber, pulse: false },
    disconnected: { label: 'OFFLINE', color: colors.red, pulse: false },
  }[status] || { label: 'CONNECTING', color: colors.textSecondary, pulse: true };

  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 5,
      padding: '3px 10px', borderRadius: 14, fontSize: 10, fontWeight: 600,
      background: `${config.color}15`, color: config.color, fontFamily: mono,
      border: `1px solid ${config.color}30`,
    }}>
      <span style={{
        width: 6, height: 6, borderRadius: '50%', background: config.color,
        ...(config.pulse ? { animation: 'signal-pulse 1.5s ease-in-out infinite' } : {}),
      }} />
      {config.label}
    </span>
  );
}

// ── Active Signals by Strategy panel ──
function StrategyBreakdown({ signals }) {
  const breakdown = useMemo(() => {
    const map = {};
    signals.forEach(sig => {
      const name = sig.strategy || 'Unknown';
      if (!map[name]) map[name] = { count: 0, buyCount: 0, sellCount: 0, totalConf: 0 };
      map[name].count++;
      map[name].totalConf += (sig.confidence || 0);
      const d = sig.direction?.toLowerCase();
      if (d === 'long' || d === 'buy') map[name].buyCount++;
      else map[name].sellCount++;
    });
    return Object.entries(map)
      .map(([name, data]) => ({ name, ...data, avgConf: data.totalConf / data.count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 12);
  }, [signals]);

  if (breakdown.length === 0) return null;

  return (
    <div style={{
      background: colors.surface, border: `1px solid ${colors.border}`,
      borderRadius: 10, padding: 16,
    }}>
      <div style={{
        fontSize: 11, color: colors.textSecondary, textTransform: 'uppercase',
        letterSpacing: '0.5px', marginBottom: 10, fontWeight: 600,
      }}>
        Active Signals by Strategy
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: 8 }}>
        {breakdown.map(s => {
          const tier = getSignalTier(s.avgConf);
          return (
            <div key={s.name} style={{
              display: 'flex', alignItems: 'center', gap: 8, padding: '8px 10px',
              background: colors.surface2, borderRadius: 6, border: `1px solid ${colors.border}`,
            }}>
              <span style={{
                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                minWidth: 22, height: 22, borderRadius: 11,
                background: `${colors.blue}20`, color: colors.blue,
                fontSize: 11, fontWeight: 700, fontFamily: mono,
              }}>
                {s.count}
              </span>
              <div style={{ flex: 1, overflow: 'hidden' }}>
                <div style={{
                  fontSize: 11, fontWeight: 600, color: colors.textPrimary,
                  overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                }}>
                  {s.name.replace(/_/g, ' ')}
                </div>
                <div style={{ display: 'flex', gap: 6, fontSize: 9, color: colors.textSecondary, marginTop: 2 }}>
                  <span style={{ color: colors.green }}>{s.buyCount}B</span>
                  <span style={{ color: colors.red }}>{s.sellCount}S</span>
                  <span style={{ color: tier.color }}>{Math.round(s.avgConf * 100)}% avg</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Signal Performance Stats section ──
function SignalPerformance({ strategies }) {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      const data = await api('/signals/performance');
      if (data) setStats(data);
      setLoading(false);
    })();
  }, []);

  if (loading) return (
    <div style={{ padding: 20, color: colors.textSecondary, fontSize: 13 }}>
      Loading signal performance...
    </div>
  );

  if (!stats || !stats.strategies || stats.strategies.length === 0) {
    if (!strategies || strategies.length === 0) return null;
    const promoted = strategies.filter(s => s.promoted);
    const sorted = [...promoted].sort((a, b) => (b.profit_factor || 0) - (a.profit_factor || 0));
    const best = sorted[0];
    const worst = sorted[sorted.length - 1];
    const avgWin = promoted.reduce((s, v) => s + (v.win_rate || 0), 0) / (promoted.length || 1);

    return (
      <div style={{
        background: colors.surface, border: `1px solid ${colors.border}`,
        borderRadius: 10, padding: 20, marginBottom: 16,
      }}>
        <h3 style={{ margin: '0 0 16px', fontSize: 14, fontWeight: 700, color: colors.textPrimary }}>
          Signal Performance (from backtest data)
        </h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 12 }}>
          <StatCard label="Promoted Strategies" value={promoted.length} color={colors.blue} />
          <StatCard label="Avg Win Rate" value={avgWin > 1 ? `${avgWin.toFixed(1)}%` : `${(avgWin * 100).toFixed(1)}%`} color={colors.green} />
          <StatCard label="Best (Profit Factor)" value={best ? `${best.name} (${(best.profit_factor || 0).toFixed(2)})` : '--'} color={colors.green} small />
          <StatCard label="Worst (Profit Factor)" value={worst ? `${worst.name} (${(worst.profit_factor || 0).toFixed(2)})` : '--'} color={colors.red} small />
        </div>
      </div>
    );
  }

  return (
    <div style={{
      background: colors.surface, border: `1px solid ${colors.border}`,
      borderRadius: 10, padding: 20, marginBottom: 16,
    }}>
      <h3 style={{ margin: '0 0 16px', fontSize: 14, fontWeight: 700, color: colors.textPrimary }}>
        Signal Performance
      </h3>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 12 }}>
        <StatCard label="Total Strategies" value={stats.total_strategies} color={colors.blue} />
        <StatCard label="Avg Signal Accuracy" value={stats.avg_accuracy != null ? `${(stats.avg_accuracy * 100).toFixed(1)}%` : '--'} color={colors.green} />
        <StatCard label="Avg Return/Signal" value={stats.avg_return != null ? `${(stats.avg_return * 100).toFixed(2)}%` : '--'} color={(stats.avg_return || 0) >= 0 ? colors.green : colors.red} />
        <StatCard label="Best This Week" value={stats.best_strategy || '--'} color={colors.green} small />
        <StatCard label="Worst This Week" value={stats.worst_strategy || '--'} color={colors.red} small />
        {stats.peak_hour != null && (
          <StatCard label="Peak Signal Hour" value={`${stats.peak_hour}:00`} color={colors.purple} />
        )}
      </div>

      {stats.strategies && stats.strategies.length > 0 && (
        <div style={{ marginTop: 16 }}>
          <div style={{ fontSize: 11, color: colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 8 }}>
            Accuracy by Strategy (Top 10)
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {stats.strategies.slice(0, 10).map((s) => (
              <div key={s.name} style={{
                display: 'flex', alignItems: 'center', gap: 8, padding: '4px 0',
              }}>
                <span style={{ fontSize: 12, color: colors.textSecondary, width: 160, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {s.name}
                </span>
                <div style={{ flex: 1, height: 4, background: colors.surface2, borderRadius: 2, overflow: 'hidden' }}>
                  <div style={{
                    width: `${Math.min(100, (s.accuracy || 0) * 100)}%`, height: '100%',
                    background: (s.accuracy || 0) >= 0.55 ? colors.green : (s.accuracy || 0) >= 0.45 ? colors.amber : colors.red,
                    borderRadius: 2,
                  }} />
                </div>
                <span style={{ fontSize: 11, fontWeight: 600, color: colors.textPrimary, width: 40, textAlign: 'right', fontFamily: mono }}>
                  {((s.accuracy || 0) * 100).toFixed(0)}%
                </span>
                <span style={{ fontSize: 10, color: colors.textSecondary, width: 50, textAlign: 'right' }}>
                  {s.avg_return != null ? `${(s.avg_return * 100).toFixed(1)}%` : '--'}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function StatCard({ label, value, color, small }) {
  return (
    <div style={{
      background: colors.surface2, borderRadius: 8, padding: '10px 14px',
      border: `1px solid ${colors.border}`,
    }}>
      <div style={{ fontSize: 10, color: colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 4 }}>
        {label}
      </div>
      <div style={{
        fontSize: small ? 12 : 18, fontWeight: 700, color: color || colors.textPrimary,
        fontFamily: mono, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
      }}>
        {value}
      </div>
    </div>
  );
}

export default function SignalsPage() {
  usePageTitle('Signals');
  const isMobile = useIsMobile();
  const { signals, strategies, count, signalsGeneratedAt, loading, refresh } = useSignals();

  // SSE real-time connection
  const [sseStatus, setSseStatus] = useState('disconnected');
  const [sseSignals, setSseSignals] = useState([]);
  const sseRef = useRef(null);
  const sseReconnectTimer = useRef(null);

  // Filters
  const [regionFilter, setRegionFilter] = useState('');
  const [strategyFilter, setStrategyFilter] = useState('');
  const [directionFilter, setDirectionFilter] = useState('');
  const [tierFilter, setTierFilter] = useState('');
  const [showPerformance, setShowPerformance] = useState(false);
  const [showStrategyBreakdown, setShowStrategyBreakdown] = useState(true);

  // SSE live feed for new signals
  const [liveFeed, setLiveFeed] = useState([]);

  // ── SSE Connection ──
  useEffect(() => {
    const API_BASE = getApiBase();
    let es;
    let reconnectAttempts = 0;

    function connect() {
      try {
        es = new EventSource(`${API_BASE}/realtime/stream`);
        sseRef.current = es;

        es.onopen = () => {
          setSseStatus('connected');
          reconnectAttempts = 0;
        };

        es.addEventListener('signal', (ev) => {
          try {
            const sig = JSON.parse(ev.data);
            // Add to SSE signals (newest first, cap at 300)
            setSseSignals(prev => {
              const key = `${sig.symbol}-${sig.strategy}-${sig.direction}`;
              // Dedupe: replace existing signal for same symbol+strategy+direction
              const filtered = prev.filter(p =>
                `${p.symbol}-${p.strategy}-${p.direction}` !== key
              );
              return [sig, ...filtered].slice(0, 300);
            });
            // Add to live feed ticker (most recent 20 for the feed display)
            setLiveFeed(prev => [
              { ...sig, _ts: Date.now() },
              ...prev
            ].slice(0, 20));
          } catch { /* ignore parse errors */ }
        });

        es.addEventListener('heartbeat', () => {
          // Keep-alive acknowledged
        });

        es.onerror = () => {
          setSseStatus('polling');
          es.close();
          // Reconnect with exponential backoff
          reconnectAttempts++;
          const delay = Math.min(5000 * Math.pow(2, reconnectAttempts - 1), 60000);
          sseReconnectTimer.current = setTimeout(connect, delay);
        };
      } catch {
        setSseStatus('polling');
      }
    }

    connect();

    return () => {
      if (es) es.close();
      if (sseReconnectTimer.current) clearTimeout(sseReconnectTimer.current);
    };
  }, []);

  // Merge SSE signals into polled signals. SSE signals take priority (newer).
  const mergedSignals = useMemo(() => {
    if (sseSignals.length === 0) return signals;

    // Build a map from polled signals
    const map = new Map();
    signals.forEach(sig => {
      const key = `${sig.symbol}-${sig.strategy}-${sig.direction}`;
      map.set(key, sig);
    });
    // SSE signals override
    sseSignals.forEach(sig => {
      const key = `${sig.symbol}-${sig.strategy}-${sig.direction}`;
      map.set(key, sig);
    });
    return Array.from(map.values());
  }, [signals, sseSignals]);

  const mergedCount = mergedSignals.length || count;

  // Auto-refresh countdown
  const [countdown, setCountdown] = useState(30);
  useEffect(() => {
    const iv = setInterval(() => {
      setCountdown(prev => prev <= 1 ? 30 : prev - 1);
    }, 1000);
    return () => clearInterval(iv);
  }, []);

  const handleRefresh = useCallback(() => {
    refresh();
    setCountdown(30);
  }, [refresh]);

  // Derive unique values for filter dropdowns
  const regions = useMemo(() => {
    const set = new Set(mergedSignals.map(s => s.region).filter(Boolean));
    return [...set].sort();
  }, [mergedSignals]);

  const strategyNames = useMemo(() => {
    const set = new Set(mergedSignals.map(s => s.strategy).filter(Boolean));
    return [...set].sort();
  }, [mergedSignals]);

  // Apply filters
  const filtered = useMemo(() => {
    let out = mergedSignals;
    if (regionFilter) out = out.filter(s => s.region === regionFilter);
    if (strategyFilter) out = out.filter(s => s.strategy === strategyFilter);
    if (directionFilter) out = out.filter(s => {
      const d = s.direction?.toLowerCase();
      if (directionFilter === 'buy') return d === 'long' || d === 'buy';
      if (directionFilter === 'sell') return d === 'short' || d === 'sell';
      return true;
    });
    if (tierFilter) {
      out = out.filter(s => {
        const tier = getSignalTier(s.confidence);
        if (tierFilter === 'ultra') return tier.label === 'ULTRA';
        if (tierFilter === 'high') return tier.label === 'HIGH CONVICTION';
        if (tierFilter === 'standard') return tier.label === 'STANDARD';
        return true;
      });
    }
    // Sort by confidence descending
    return [...out].sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
  }, [mergedSignals, regionFilter, strategyFilter, directionFilter, tierFilter]);

  // Tier counts for KPIs
  const tierCounts = useMemo(() => {
    let ultra = 0, high = 0, standard = 0;
    mergedSignals.forEach(s => {
      const c = s.confidence || 0;
      if (c >= 0.95) ultra++;
      else if (c >= 0.70) high++;
      else standard++;
    });
    return { ultra, high, standard };
  }, [mergedSignals]);

  const signalAge = getSignalAge(null, signalsGeneratedAt);

  const selectStyle = {
    background: colors.surface2, border: `1px solid ${colors.border}`, borderRadius: 6,
    padding: '6px 10px', color: colors.textPrimary, fontFamily: mono, fontSize: 12,
    outline: 'none', cursor: 'pointer',
  };

  // Mobile layout
  if (isMobile) {
    if (loading) return <SkeletonMobile kpiCount={3} cardCount={6} />;
    return (
      <div className="mobile-page" style={{ position: 'relative' }}>
        <style>{`@keyframes signal-pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.3; } }`}</style>
        <div className="mobile-page-header">
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <h1>Live Signals</h1>
            <ConnectionBadge status={sseStatus} />
          </div>
          <p>{filtered.length} active signals</p>
        </div>
        <div className="mobile-kpi-grid">
          <div className="mobile-kpi">
            <div className="mobile-kpi-label">Total</div>
            <div className="mobile-kpi-value" style={{ color: colors.blue }}>{mergedCount}</div>
          </div>
          <div className="mobile-kpi">
            <div className="mobile-kpi-label" style={{ color: colors.gold }}>ULTRA</div>
            <div className="mobile-kpi-value" style={{ color: colors.gold }}>{tierCounts.ultra}</div>
          </div>
          <div className="mobile-kpi">
            <div className="mobile-kpi-label" style={{ color: colors.blue }}>HIGH</div>
            <div className="mobile-kpi-value" style={{ color: colors.blue }}>{tierCounts.high}</div>
          </div>
        </div>

        {/* Mobile filters */}
        <div style={{ display: 'flex', gap: 8, padding: '0 16px', marginBottom: 12, flexWrap: 'wrap' }}>
          <select value={directionFilter} onChange={e => setDirectionFilter(e.target.value)} style={{ ...selectStyle, flex: 1 }}>
            <option value="">All Directions</option>
            <option value="buy">Buy/Long</option>
            <option value="sell">Sell/Short</option>
          </select>
          <select value={tierFilter} onChange={e => setTierFilter(e.target.value)} style={{ ...selectStyle, flex: 1 }}>
            <option value="">All Tiers</option>
            <option value="ultra">ULTRA</option>
            <option value="high">HIGH CONVICTION</option>
            <option value="standard">STANDARD</option>
          </select>
        </div>

        {/* Live feed ticker on mobile */}
        {liveFeed.length > 0 && (
          <div style={{ padding: '0 16px', marginBottom: 12 }}>
            <div style={{
              background: colors.surface, border: `1px solid ${colors.border}`, borderRadius: 8,
              padding: 10, maxHeight: 80, overflow: 'hidden',
            }}>
              <div style={{ fontSize: 9, color: colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 6 }}>
                Live Feed
              </div>
              {liveFeed.slice(0, 3).map((sig, i) => (
                <div key={`feed-${i}`} style={{
                  display: 'flex', alignItems: 'center', gap: 6, fontSize: 11, padding: '2px 0',
                  color: colors.textPrimary,
                }}>
                  <span style={{ color: colors.blue, fontWeight: 700, fontFamily: mono }}>{sig.symbol}</span>
                  <DirectionBadge direction={sig.direction} />
                  <TierBadge confidence={sig.confidence} />
                  <span style={{ marginLeft: 'auto', fontSize: 9, color: colors.textSecondary }}>
                    {sig.strategy?.replace(/_/g, ' ')}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {filtered.length > 0 ? filtered.slice(0, 50).map((sig, i) => {
          const age = getSignalAge(sig.date, signalsGeneratedAt);
          return (
            <div className="mobile-card" key={`${sig.symbol}-${sig.strategy}-${i}`} style={{
              borderLeft: `3px solid ${sig.direction === 'long' || sig.direction === 'buy' ? colors.green : colors.red}`,
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
                <span style={{ fontFamily: mono, fontSize: 15, fontWeight: 700, color: colors.blue }}>
                  {sig.symbol}
                </span>
                <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
                  <TierBadge confidence={sig.confidence} />
                  <DirectionBadge direction={sig.direction} />
                </div>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 12, color: colors.textSecondary }}>{sig.strategy?.replace(/_/g, ' ')}</span>
                <ConfidenceBar value={sig.confidence} />
              </div>
              <div style={{ marginTop: 4, display: 'flex', justifyContent: 'space-between' }}>
                <AgeBadge age={age} />
                <span style={{ fontSize: 10, color: colors.textSecondary }}>{sig.region?.toUpperCase()}</span>
              </div>
            </div>
          );
        }) : (
          <div className="mobile-empty">No signals matching filters</div>
        )}
      </div>
    );
  }

  // Desktop layout
  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.25, ease: [0.4, 0, 0.2, 1] }}
      style={{
        height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden',
        padding: '20px 24px', gap: 16, fontFamily: mono, color: colors.textPrimary,
        backgroundColor: colors.bg, position: 'relative',
      }}
    >
      <style>{`
        @keyframes signal-pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.3; } }
        @keyframes spin-signals { to { transform: rotate(360deg); } }
        @keyframes flash-in { 0% { background: rgba(96,165,250,0.2); } 100% { background: transparent; } }
      `}</style>

      {/* Header */}
      <div style={{ marginBottom: 4 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <h1 style={{ margin: 0, fontSize: 28, fontWeight: 700 }}>Live Signals</h1>
          <span style={{
            display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
            minWidth: 28, height: 28, borderRadius: 14,
            background: `${colors.blue}20`, color: colors.blue,
            fontSize: 14, fontWeight: 700, padding: '0 8px', fontFamily: mono,
          }}>
            {mergedCount}
          </span>
          <AgeBadge age={signalAge} />
          <ConnectionBadge status={sseStatus} />
        </div>
        <p style={{ margin: '6px 0 0', fontSize: 13, color: colors.textSecondary }}>
          Real-time Aura Alpha trading signals across all promoted strategies
        </p>
      </div>

      {/* KPI row with tier counts */}
      <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
        <KPIChip label="Total Signals" value={mergedCount} color={colors.blue} />
        <KPIChip label="ULTRA" value={tierCounts.ultra} color={colors.gold} />
        <KPIChip label="HIGH CONVICTION" value={tierCounts.high} color={colors.blue} />
        <KPIChip label="STANDARD" value={tierCounts.standard} color={colors.textSecondary} />
        <KPIChip
          label="Buy / Long"
          value={mergedSignals.filter(s => s.direction === 'long' || s.direction === 'buy').length}
          color={colors.green}
        />
        <KPIChip
          label="Sell / Short"
          value={mergedSignals.filter(s => s.direction === 'short' || s.direction === 'sell').length}
          color={colors.red}
        />

        {/* Auto-refresh / SSE indicator */}
        <div style={{
          marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 8,
          background: colors.surface, border: `1px solid ${colors.border}`,
          borderRadius: 10, padding: '6px 14px', fontSize: 11, color: colors.textSecondary,
        }}>
          {sseStatus === 'connected' ? (
            <>
              <span style={{
                width: 8, height: 8, borderRadius: '50%', background: colors.green,
                animation: 'signal-pulse 2s ease-in-out infinite',
              }} />
              Streaming live
            </>
          ) : (
            <>
              <span style={{
                width: 8, height: 8, borderRadius: '50%', background: colors.amber,
              }} />
              Polling in {countdown}s
            </>
          )}
          <motion.button
            whileTap={{ scale: 0.95 }}
            onClick={handleRefresh}
            style={{
              background: colors.blue, color: colors.bg, border: 'none', borderRadius: 6,
              padding: '4px 12px', fontFamily: mono, fontSize: 11, fontWeight: 600, cursor: 'pointer',
            }}
          >
            Refresh Now
          </motion.button>
        </div>
      </div>

      {/* Live feed ticker (shows most recent SSE signals) */}
      {liveFeed.length > 0 && (
        <div style={{
          background: colors.surface, border: `1px solid ${colors.border}`,
          borderRadius: 10, padding: '10px 16px',
          display: 'flex', alignItems: 'center', gap: 16, overflow: 'hidden',
        }}>
          <span style={{
            fontSize: 9, color: colors.green, textTransform: 'uppercase',
            letterSpacing: '0.5px', fontWeight: 700, whiteSpace: 'nowrap',
          }}>
            LIVE FEED
          </span>
          <div style={{ display: 'flex', gap: 16, overflow: 'hidden', flex: 1 }}>
            {liveFeed.slice(0, 8).map((sig, i) => (
              <motion.div
                key={`feed-${sig.symbol}-${sig._ts}-${i}`}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.3 }}
                style={{
                  display: 'flex', alignItems: 'center', gap: 6,
                  padding: '3px 10px', borderRadius: 6,
                  background: colors.surface2, whiteSpace: 'nowrap',
                }}
              >
                <span style={{ fontWeight: 700, color: colors.blue, fontSize: 12, fontFamily: mono }}>
                  {sig.symbol}
                </span>
                <DirectionBadge direction={sig.direction} />
                <TierBadge confidence={sig.confidence} />
                <span style={{ fontSize: 10, color: colors.textSecondary }}>
                  {sig.strategy?.replace(/_/g, ' ')}
                </span>
              </motion.div>
            ))}
          </div>
        </div>
      )}

      {/* Filter bar */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap',
      }}>
        <label style={{ fontSize: 11, color: colors.textSecondary, display: 'flex', alignItems: 'center', gap: 4 }}>
          Region
          <select value={regionFilter} onChange={e => setRegionFilter(e.target.value)} style={selectStyle}>
            <option value="">All</option>
            {regions.map(r => <option key={r} value={r}>{r.toUpperCase()}</option>)}
          </select>
        </label>
        <label style={{ fontSize: 11, color: colors.textSecondary, display: 'flex', alignItems: 'center', gap: 4 }}>
          Strategy
          <select value={strategyFilter} onChange={e => setStrategyFilter(e.target.value)} style={{ ...selectStyle, maxWidth: 200 }}>
            <option value="">All</option>
            {strategyNames.map(s => <option key={s} value={s}>{s.replace(/_/g, ' ')}</option>)}
          </select>
        </label>
        <label style={{ fontSize: 11, color: colors.textSecondary, display: 'flex', alignItems: 'center', gap: 4 }}>
          Direction
          <select value={directionFilter} onChange={e => setDirectionFilter(e.target.value)} style={selectStyle}>
            <option value="">All</option>
            <option value="buy">Buy / Long</option>
            <option value="sell">Sell / Short</option>
          </select>
        </label>
        <label style={{ fontSize: 11, color: colors.textSecondary, display: 'flex', alignItems: 'center', gap: 4 }}>
          Tier
          <select value={tierFilter} onChange={e => setTierFilter(e.target.value)} style={selectStyle}>
            <option value="">All Tiers</option>
            <option value="ultra">ULTRA</option>
            <option value="high">HIGH CONVICTION</option>
            <option value="standard">STANDARD</option>
          </select>
        </label>

        <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>
          <motion.button
            whileTap={{ scale: 0.97 }}
            onClick={() => setShowStrategyBreakdown(p => !p)}
            style={{
              background: showStrategyBreakdown ? colors.cyan : colors.surface,
              color: showStrategyBreakdown ? colors.bg : colors.textSecondary,
              border: `1px solid ${showStrategyBreakdown ? colors.cyan : colors.border}`,
              borderRadius: 6, padding: '6px 14px', fontFamily: mono,
              fontSize: 11, fontWeight: 600, cursor: 'pointer',
            }}
          >
            {showStrategyBreakdown ? 'Hide Strategies' : 'By Strategy'}
          </motion.button>
          <motion.button
            whileTap={{ scale: 0.97 }}
            onClick={() => setShowPerformance(p => !p)}
            style={{
              background: showPerformance ? colors.purple : colors.surface,
              color: showPerformance ? colors.bg : colors.textSecondary,
              border: `1px solid ${showPerformance ? colors.purple : colors.border}`,
              borderRadius: 6, padding: '6px 14px', fontFamily: mono,
              fontSize: 11, fontWeight: 600, cursor: 'pointer',
            }}
          >
            {showPerformance ? 'Hide Stats' : 'Signal Stats'}
          </motion.button>
        </div>
      </div>

      {/* Strategy Breakdown (collapsible) */}
      <AnimatePresence>
        {showStrategyBreakdown && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2 }}
            style={{ overflow: 'hidden' }}
          >
            <StrategyBreakdown signals={mergedSignals} />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Signal Performance (collapsible) */}
      <AnimatePresence>
        {showPerformance && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2 }}
            style={{ overflow: 'hidden' }}
          >
            <SignalPerformance strategies={strategies} />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Signal table */}
      <div style={{ flex: 1, overflow: 'auto' }}>
        <ExportBar
          data={filtered}
          filename="signals-export"
          columns={['Symbol', 'Strategy', 'Direction', 'Confidence', 'Tier', 'Region', 'Date']}
        />

        {loading ? (
          <div style={{ display: 'flex', justifyContent: 'center', padding: 60 }}>
            <div style={{
              width: 36, height: 36, border: `3px solid ${colors.border}`,
              borderTop: `3px solid ${colors.blue}`, borderRadius: '50%',
              animation: 'spin-signals 0.8s linear infinite',
            }} />
          </div>
        ) : filtered.length === 0 ? (
          <div style={{
            background: colors.surface, border: `1px solid ${colors.border}`,
            borderRadius: 10, padding: 40, textAlign: 'center', color: colors.textSecondary, fontSize: 14,
          }}>
            {mergedSignals.length === 0
              ? 'No signals available. Signals are generated during market hours by the Aura Alpha engine.'
              : 'No signals match your current filters. Try adjusting the filters above.'
            }
          </div>
        ) : (
          <div style={{
            background: colors.surface, border: `1px solid ${colors.border}`,
            borderRadius: 10, overflow: 'auto',
          }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
              <thead>
                <tr style={{ borderBottom: `1px solid ${colors.border}` }}>
                  {['Symbol', 'Strategy', 'Direction', 'Confidence', 'Tier', 'Age', 'Region'].map(h => (
                    <th key={h} style={{
                      padding: '12px 16px', textAlign: 'left', color: colors.textSecondary,
                      fontWeight: 600, fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.5px',
                      whiteSpace: 'nowrap', position: 'sticky', top: 0, background: colors.surface,
                    }}>
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filtered.map((sig, idx) => {
                  const age = getSignalAge(sig.date, signalsGeneratedAt);
                  // Check if this signal came from SSE (recently)
                  const isFromSse = sseSignals.some(s =>
                    s.symbol === sig.symbol && s.strategy === sig.strategy && s.direction === sig.direction
                  );
                  return (
                    <motion.tr
                      key={`${sig.symbol}-${sig.strategy}-${idx}`}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: Math.min(idx * 0.01, 0.5) }}
                      style={{
                        borderBottom: idx < filtered.length - 1 ? `1px solid ${colors.border}` : 'none',
                        cursor: 'default',
                        ...(isFromSse ? { animation: 'flash-in 2s ease-out' } : {}),
                      }}
                      onMouseEnter={e => e.currentTarget.style.background = colors.surface2}
                      onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
                    >
                      <td style={{ padding: '10px 16px', fontWeight: 700, color: colors.blue }}>
                        {sig.symbol}
                      </td>
                      <td style={{ padding: '10px 16px', color: colors.textSecondary, fontSize: 12 }}>
                        {sig.strategy?.replace(/_/g, ' ')}
                      </td>
                      <td style={{ padding: '10px 16px' }}>
                        <DirectionBadge direction={sig.direction} />
                      </td>
                      <td style={{ padding: '10px 16px' }}>
                        <ConfidenceBar value={sig.confidence} />
                      </td>
                      <td style={{ padding: '10px 16px' }}>
                        <TierBadge confidence={sig.confidence} />
                      </td>
                      <td style={{ padding: '10px 16px' }}>
                        <AgeBadge age={age} />
                      </td>
                      <td style={{ padding: '10px 16px', fontSize: 11, color: colors.textSecondary }}>
                        {sig.region?.toUpperCase()}
                      </td>
                    </motion.tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Signal count footer */}
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        padding: '8px 0', fontSize: 11, color: colors.textSecondary,
      }}>
        <span>
          Showing {filtered.length} of {mergedCount} signals
          {sseSignals.length > 0 && (
            <span style={{ color: colors.green, marginLeft: 8 }}>
              ({sseSignals.length} via SSE)
            </span>
          )}
        </span>
        <span>
          Generated: {signalsGeneratedAt > 0
            ? new Date(signalsGeneratedAt * 1000).toLocaleString()
            : 'Unknown'
          }
        </span>
      </div>
      <RegulatoryDisclaimer compact />
    </motion.div>
  );
}

function KPIChip({ label, value, color }) {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 8,
      background: colors.surface, border: `1px solid ${colors.border}`,
      borderRadius: 10, padding: '8px 14px',
    }}>
      <span style={{ fontSize: 11, color: colors.textSecondary }}>{label}</span>
      <span style={{
        display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
        minWidth: 24, height: 24, borderRadius: 14,
        background: `${color}18`, color: color,
        fontSize: 13, fontWeight: 700, padding: '0 6px', fontFamily: mono,
      }}>
        {value}
      </span>
    </div>
  );
}
